function defaultState() {
  return { route: 'dashboard', theme: 'dark', track: 'all', lesson: 'l1', card: 0, questionFilter: 'all', done: [], known: {}, quiz: {}, caseAnswers: {}, xp: 0, streak: 1, sync: 'offline', userEmail: '', lastLocalUpdate: new Date().toISOString(), lastRemoteUpdate: '' };
}

let state = loadState();
let supabaseClient = null;
let cloudUser = null;
let cloudTimer = null;
let isHydrating = false;

function loadState() {
  try { return { ...defaultState(), ...JSON.parse(localStorage.getItem(STORE_KEY) || '{}') }; }
  catch { return defaultState(); }
}

function saveState(reason = 'change') {
  state.lastLocalUpdate = new Date().toISOString();
  localStorage.setItem(STORE_KEY, JSON.stringify(state));
  scheduleCloudSave(reason);
}

function safe(value) { return String(value ?? '').replace(/[&<>"']/g, char => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char])); }

function notify(message) {
  toast.textContent = message;
  toast.classList.remove('hidden');
  clearTimeout(notify.timer);
  notify.timer = setTimeout(() => toast.classList.add('hidden'), 2600);
}

function addXp(amount, message) {
  state.xp += amount;
  notify(`+${amount} XP · ${message}`);
  saveState(message);
}

function mastery() {
  const lessonScore = state.done.length / catalog.lessons.length * 35;
  const cardScore = Object.keys(state.known).length / cards.length * 20;
  const quizScore = Object.values(state.quiz).filter(Boolean).length / questions.length * 30;
  const caseScore = Object.keys(state.caseAnswers).length / cases.length * 15;
  return Math.round(Math.min(100, lessonScore + cardScore + quizScore + caseScore));
}

function currentLesson() { return catalog.lessons.find(item => item.id === state.lesson) || catalog.lessons[0]; }
function filteredLessons() { return state.track === 'all' ? catalog.lessons : catalog.lessons.filter(item => item.track === state.track); }
function filteredQuestions() { return state.questionFilter === 'all' ? questions : questions.filter(item => item.track === state.questionFilter); }
function routeTo(route) { state.route = route; saveState('route'); render(); history.replaceState(null, '', '#' + route); }
function updateNav() { document.querySelectorAll('[data-route]').forEach(btn => btn.classList.toggle('active', btn.dataset.route === state.route)); }
function trackTitle(id) { const track = catalog.tracks.find(item => item.id === id); return track ? track.title : 'Alle Tracks'; }

function dashboard() {
  const nextLesson = catalog.lessons.find(item => !state.done.includes(item.id));
  const answered = Object.keys(state.quiz).length;
  return `<section class="hero glass"><div class="hero-copy"><p class="eyebrow">Skillio Learning OS</p><h1>Change Management lernen wie ein Profi.</h1><p class="lead">Klarer aufgebaut: Curriculum, Übungsbank, Case-Simulator und echter Supabase-Sync nach Login. Fokus: schnelle Lernwirkung und Management-Handlungsfähigkeit.</p><div class="badges"><span class="badge ok">${cloudUser ? 'DB verbunden' : 'DB bereit'}</span><span class="badge">${questions.length} Quizfragen</span><span class="badge amber">${cards.length} Lernkarten</span><span class="badge muted">${catalog.lessons.length} Lektionen</span></div><div class="actions"><button class="pill primary" data-route="learn">Curriculum starten</button><button class="pill secondary" data-route="practice">Training öffnen</button><button class="pill ghost" data-route="profile">DB / Login</button></div></div><aside class="center"><article class="level"><p class="eyebrow">Mastery</p><div class="num">${mastery()}%</div><h3>Level ${Math.floor(state.xp / 220) + 1} · ${state.xp} XP</h3><p>${cloudUser ? `Cloud Sync aktiv für ${safe(state.userEmail)}` : 'Melde dich im Profil an, dann wird Fortschritt in Supabase gespeichert.'}</p><div class="bar"><i style="width:${mastery()}%"></i></div></article><div class="kpis"><article class="kpi"><small>Lektionen</small><strong>${state.done.length}/${catalog.lessons.length}</strong></article><article class="kpi"><small>Quiz</small><strong>${answered}/${questions.length}</strong></article><article class="kpi"><small>Cases</small><strong>${Object.keys(state.caseAnswers).length}/${cases.length}</strong></article><article class="kpi"><small>Sync</small><strong>${safe(state.sync)}</strong></article></div></aside></section><section class="grid four">${catalog.tracks.map(track => `<article class="card module"><div class="ico">${track.icon}</div><p class="eyebrow">${safe(track.title)}</p><h3>${safe(track.description)}</h3><p>${catalog.lessons.filter(l => l.track === track.id && state.done.includes(l.id)).length}/${catalog.lessons.filter(l => l.track === track.id).length} Lektionen erledigt</p><button class="pill secondary" data-track-open="${track.id}">Track öffnen</button></article>`).join('')}</section><section class="grid two"><article class="panel glass"><div class="head"><div><p class="eyebrow">Nächste beste Aktion</p><h2>${nextLesson ? safe(nextLesson.title) : 'Alle Lektionen erledigt'}</h2></div><span class="badge">+40 XP</span></div>${nextLesson ? `<p>${safe(nextLesson.drill)}</p><div class="actions"><button class="pill primary" data-lesson="${nextLesson.id}">Jetzt lernen</button><button class="pill secondary" data-route="practice">Erst üben</button></div>` : '<div class="empty">Gehe ins Training und löse alle Quizfragen oder Cases.</div>'}</article><article class="panel glass"><div class="head"><div><p class="eyebrow">DB Status</p><h2>${cloudUser ? 'Supabase speichert aktiv' : 'Supabase noch nicht angemeldet'}</h2></div></div><p>${cloudUser ? 'Jede Lernaktion löst einen Upsert in skillio.user_learning_state aus.' : 'Im Profil Anon Key prüfen und mit E-Mail/Passwort anmelden. Danach wird automatisch gespeichert.'}</p><div class="actions"><button class="pill secondary" data-route="profile">DB Setup öffnen</button><button class="pill ghost" data-sync-now>Jetzt synchronisieren</button></div></article></section>`;
}

function learn() {
  const lesson = currentLesson();
  const list = filteredLessons();
  return `<section class="panel glass"><div class="head"><div><p class="eyebrow">Curriculum</p><h2>${safe(catalog.category.title)}</h2><p>${safe(catalog.category.promise)}</p></div><span class="badge">${state.done.length}/${catalog.lessons.length} abgeschlossen</span></div><div class="filter-row"><button class="tab ${state.track === 'all' ? 'active' : ''}" data-track="all">Alle</button>${catalog.tracks.map(track => `<button class="tab ${state.track === track.id ? 'active' : ''}" data-track="${track.id}">${track.icon} ${safe(track.title)}</button>`).join('')}</div></section><section class="course-shell"><aside class="side">${list.map(item => `<button class="cardbtn ${item.id === lesson.id ? 'active' : ''}" data-lesson="${item.id}"><small>${state.done.includes(item.id) ? '✓ Abgeschlossen' : `${safe(trackTitle(item.track))} · ${item.time} Min`}</small><strong>${safe(item.title)}</strong><span>${safe(item.drill)}</span></button>`).join('')}</aside><article class="view"><div class="lesson-meta"><span class="badge">${safe(trackTitle(lesson.track))}</span><span class="badge muted">${lesson.time} Minuten</span><span class="badge amber">${safe(lesson.level)}</span></div><h2>${safe(lesson.title)}</h2><div class="body"><p>${safe(lesson.body)}</p><blockquote>${safe(lesson.rule)}</blockquote><article class="casebox"><strong>Praxisdrill</strong><p>${safe(lesson.drill)}</p></article></div><div class="foot"><button class="pill secondary" data-route="practice">Dazu üben</button><button class="pill primary" data-done="${lesson.id}">${state.done.includes(lesson.id) ? 'Bereits verstanden' : 'Als verstanden markieren'}</button></div></article></section>`;
}

function practice() { return `<section class="panel glass"><div class="head"><div><p class="eyebrow">Training</p><h2>Übungsbank statt Demo-Fragen.</h2><p>Mehr Fragen, sauber nach Tracks filterbar. Jede Antwort speichert lokal und nach Login in Supabase.</p></div><span class="badge">${questions.length} Fragen</span></div><div class="filter-row"><button class="tab ${state.questionFilter === 'all' ? 'active' : ''}" data-qfilter="all">Alle Fragen</button>${catalog.tracks.map(track => `<button class="tab ${state.questionFilter === track.id ? 'active' : ''}" data-qfilter="${track.id}">${safe(track.title)}</button>`).join('')}</div></section>${quizView()}${flashView()}${caseView()}${heatView()}${roadmapView()}`; }

function quizView() {
  const qs = filteredQuestions();
  return `<section class="panel glass"><div class="head"><div><p class="eyebrow">Quiz Engine</p><h2>${qs.length} Fragen · ${safe(trackTitle(state.questionFilter))}</h2></div><button class="pill ghost" data-resetquiz>Quiz zurücksetzen</button></div><div class="question-list">${qs.map((item) => { const qi = questions.indexOf(item); const answered = Object.prototype.hasOwnProperty.call(state.quiz, qi); return `<article class="quiz compact"><p class="eyebrow">${safe(trackTitle(item.track))}</p><h3>${safe(item.q)}</h3><div class="grid two">${item.o.map((choice, i) => `<button class="choice ${answered && i === item.a ? 'correct' : ''} ${answered && !state.quiz[qi] && i !== item.a ? 'wrong' : ''}" data-q="${qi}" data-choice="${i}" ${answered ? 'disabled' : ''}>${safe(choice)}</button>`).join('')}</div>${answered ? `<div class="feedback"><strong>${state.quiz[qi] ? 'Richtig.' : 'Noch schärfer denken.'}</strong> ${safe(item.x)}</div>` : ''}</article>`; }).join('')}</div></section>`;
}

function flashView() {
  const card = cards[state.card] || cards[0];
  const known = state.known[state.card];
  return `<section class="panel glass"><div class="head"><div><p class="eyebrow">Lernkarten</p><h2>${Object.keys(state.known).length}/${cards.length} gemeistert</h2></div><span class="badge">Spaced-Repetition-ready</span></div><div class="flash"><aside class="deck">${cards.map((item, i) => `<button class="cardbtn ${i === state.card ? 'active' : ''}" data-card="${i}"><small>${state.known[i] ? '✓ Gemeistert' : 'Lernkarte ' + (i + 1)}</small><strong>${safe(item[0])}</strong></button>`).join('')}</aside><article id="activeFlash" class="flashcard ${known ? 'revealed' : ''}"><div><span class="badge">Transferkarte</span><div class="question">${safe(card[0])}</div><div class="answer"><strong>Antwort:</strong> ${safe(card[1])}</div><div class="actions" style="justify-content:center;margin-top:18px"><button class="pill secondary" data-reveal>Antwort zeigen</button><button class="pill primary" data-master>Gemeistert</button></div></div></article></div></section>`;
}

function caseView() { return `<section class="panel glass"><div class="head"><div><p class="eyebrow">Case Simulator</p><h2>Management-Fälle</h2></div><span class="badge amber">${cases.length} Cases</span></div><div class="grid three">${cases.map(item => `<article class="casebox"><p class="eyebrow">Mini Case</p><h3>${safe(item.title)}</h3><p>${safe(item.brief)}</p><ul>${item.symptoms.map(symptom => `<li>${safe(symptom)}</li>`).join('')}</ul><textarea class="textarea" data-case-text="${item.id}" placeholder="${safe(item.prompt)}">${safe(state.caseAnswers[item.id] || '')}</textarea><div class="actions"><button class="pill primary" data-savecase="${item.id}">Antwort speichern</button><button class="pill secondary" data-model="${item.id}">Musterlogik</button></div><div id="case-${item.id}" class="feedback ${state.caseAnswers[item.id] ? '' : 'hidden'}">${state.caseAnswers[item.id] ? reviewCase(state.caseAnswers[item.id], item) : ''}</div></article>`).join('')}</div></section>`; }

function reviewCase(answer, item) {
  const text = answer.toLowerCase();
  const checks = [['Sache/Sozial/Zeit', ['sache','sozial','zeit'].every(word => text.includes(word))], ['Ownership/Mandat', text.includes('ownership') || text.includes('mandat')], ['Führung', text.includes('führung') || text.includes('management')], ['KPIs', text.includes('kpi')], ['ADKAR', text.includes('adkar') || text.includes('awareness') || text.includes('desire')]];
  const missing = checks.filter(check => !check[1]).map(check => check[0]);
  return `<strong>Skillio Review: ${5 - missing.length}/5 Qualitätsmarker.</strong> ${missing.length ? 'Noch ergänzen: ' + safe(missing.join(', ')) + '. ' : 'Managementtauglich. '}<br><br><strong>Musterlogik:</strong> ${safe(item.model)}`;
}

function heatView() { const labels = ['Awareness','Desire','Knowledge','Ability','Reinforcement']; return `<section class="panel glass"><div class="head"><div><p class="eyebrow">ADKAR Heatmap</p><h2>Barrier Points nach Zielgruppe</h2></div><span class="badge">1 kritisch · 5 stark</span></div><div class="heatrow header"><span>Zielgruppe</span>${labels.map(label => `<span>${label}</span>`).join('')}<span>Barrier Point</span></div>${heatmap.map(row => `<div class="heatrow"><strong>${safe(row[0])}</strong>${row[1].map((value, index) => `<span class="heat ${value <= 2 ? 'low' : value === 3 ? 'mid' : 'high'}" data-label="${labels[index]}">${value}</span>`).join('')}<span class="barrier">${safe(row[2])}</span></div>`).join('')}</section>`; }

function roadmapView() { const columns = [['30 Tage', ['Quellen und Lernobjekte konsolidieren','Mindestrollen pro Domäne definieren','Barrier Points je Zielgruppe bewerten','Supabase-Sync und Auth produktionsnah testen']], ['60 Tage', ['Embedded Key User mit Zeitbudget starten','Playbooks und Community etablieren','Quizbank und Casebank erweitern','Domänen an echten Datenprodukten coachen']], ['90 Tage', ['Ownership-KPIs in Führungsroutinen bringen','Governance als Guardrail operationalisieren','Abhängigkeit vom zentralen Team messen','Weitere Lernkategorien modular ergänzen']]]; return `<section class="panel glass"><div class="head"><div><p class="eyebrow">Roadmap</p><h2>30/60/90-Tage Lern- und Transformationsplan</h2></div><button class="pill secondary" data-route="coach">Mit Coach verfeinern</button></div><div class="road">${columns.map(col => `<article class="roadcol"><h3>${col[0]}</h3><ul>${col[1].map(item => `<li>${safe(item)}</li>`).join('')}</ul></article>`).join('')}</div></section>`; }

function coach() { return `<section class="panel glass"><div class="head"><div><p class="eyebrow">Skillio Coach</p><h2>Management-Antworten schärfen</h2><p>Der Coach zwingt jede Antwort in Diagnose, ADKAR, Führungsimpuls, Risiken und nächsten Schritt.</p></div></div><div class="coachgrid"><article class="quiz"><textarea id="coachIn" class="textarea" placeholder="Beschreibe eine konkrete Managementsituation..."></textarea><div class="chips"><button data-tpl="case">Case analysieren</button><button data-tpl="story">Change Story</button><button data-tpl="adkar">ADKAR Diagnose</button><button data-tpl="roadmap">30/60/90 Plan</button></div><button class="pill primary" data-coachrun>Antwort erzeugen</button></article><article><div id="coachOut" class="output">Wähle eine Vorlage oder beschreibe eine Situation.</div></article></div></section>`; }
function coachAnswer(input) { return `Situation: ${input.trim() || 'Die Domäne will kein Data Product Ownership übernehmen.'}\n\n1. Diagnose\n- Sachebene: Datenprodukt, Plattformfähigkeit oder Governance-Regel.\n- Sozial-/Interaktionsebene: Rollen, Entscheidungsspielraum, Verantwortung und Konflikte.\n- Zeitebene: Übergang von zentraler Unterstützung zu Domänenverantwortung.\n\n2. ADKAR-Hypothese\nPrüfe den Barrier Point: Awareness, Desire, Knowledge, Ability oder Reinforcement. Nicht vorschnell Training planen.\n\n3. Führungsimpuls\nFührung muss Mandat, Kapazität und Erwartung klären. Ohne Linie bleibt Ownership freiwillig und fragil.\n\n4. Management-Botschaft\nData Mesh skaliert nur, wenn Domänen Wert, Qualität, Nutzung und Weiterentwicklung ihrer Datenprodukte selbst verantworten. Der Mesh Hub unterstützt, ersetzt aber nicht fachliche Ownership.\n\n5. Nächster Schritt\nMandatsentscheidung mit Domänenleitung, Product Owner, Embedded Key User und Mesh Hub. Danach Coaching-Plan und zwei Ownership-KPIs definieren.`; }

function profile() { const config = getStoredConfig(); return `<section class="hero glass"><div class="hero-copy"><p class="eyebrow">Fortschritt & Datenbank</p><h1>Supabase-Sync ist jetzt ein echter Flow.</h1><p class="lead">Nach Auth-Login wird jeder Lernfortschritt per Upsert in <strong>skillio.user_learning_state</strong> gespeichert. Ohne Login bleibt Skillio lokal.</p><div class="badges"><span class="badge ${cloudUser ? 'ok' : 'amber'}">${cloudUser ? 'Angemeldet' : 'Nicht angemeldet'}</span><span class="badge muted">${safe(state.sync)}</span><span class="badge">${mastery()}% Mastery</span></div></div><aside class="center"><article class="level"><p class="eyebrow">XP</p><div class="num">${state.xp}</div><h3>${safe(state.userEmail || 'Lokales Profil')}</h3><div class="bar"><i style="width:${mastery()}%"></i></div></article></aside></section><section class="grid two"><article class="panel glass"><div class="head"><div><p class="eyebrow">Supabase Setup</p><h2>Verbindung</h2></div></div><label class="field"><span>Supabase URL</span><input id="sbUrl" value="${safe(config.url || DEFAULT_SUPABASE_URL)}" /></label><label class="field"><span>Anon Key</span><input id="sbKey" type="password" value="${safe(config.anonKey || '')}" placeholder="Public anon key einfügen" /></label><div class="actions"><button class="pill primary" data-save-config>Config speichern</button><button class="pill secondary" data-sync-now>Jetzt synchronisieren</button></div><p class="hint">Der Anon Key wird nur lokal im Browser gespeichert. Er wird nicht ins Repository geschrieben.</p></article><article class="panel glass"><div class="head"><div><p class="eyebrow">Login</p><h2>Private Lernstände</h2></div></div><label class="field"><span>E-Mail</span><input id="authEmail" type="email" value="${safe(state.userEmail || '')}" placeholder="du@example.com" /></label><label class="field"><span>Passwort</span><input id="authPassword" type="password" placeholder="Passwort" /></label><div class="actions"><button class="pill primary" data-login>Einloggen</button><button class="pill secondary" data-signup>Account erstellen</button><button class="pill ghost" data-logout>Logout</button></div></article></section><section class="grid two"><article class="panel glass"><div class="head"><div><p class="eyebrow">Lernstand</p><h2>Metriken</h2></div></div>${[['Lektionen',`${state.done.length}/${catalog.lessons.length}`],['Lernkarten',`${Object.keys(state.known).length}/${cards.length}`],['Quiz beantwortet',`${Object.keys(state.quiz).length}/${questions.length}`],['Quiz richtig',`${Object.values(state.quiz).filter(Boolean).length}/${questions.length}`],['Cases',`${Object.keys(state.caseAnswers).length}/${cases.length}`],['Letzter Cloud Pull',state.lastRemoteUpdate || 'noch nie']].map(row => `<div class="stat"><span>${row[0]}</span><strong>${safe(row[1])}</strong></div>`).join('')}</article><article class="panel glass"><div class="head"><div><p class="eyebrow">Danger Zone</p><h2>Lokaler Reset</h2></div></div><p>Setzt nur diesen Browser zurück. Cloud-Daten bleiben erhalten, sofern Supabase aktiviert ist.</p><div class="actions"><button class="pill danger" data-reset>Lokalen Fortschritt zurücksetzen</button></div></article></section>`; }

function getStoredConfig() { try { const local = JSON.parse(localStorage.getItem(CONFIG_KEY) || '{}'); const global = window.SKILLIO_SUPABASE_CONFIG || {}; return { url: local.url || global.url || DEFAULT_SUPABASE_URL, anonKey: local.anonKey || global.anonKey || '', schema: local.schema || global.schema || 'skillio' }; } catch { return { url: DEFAULT_SUPABASE_URL, anonKey: '', schema: 'skillio' }; } }
function saveConfigFromForm() { const url = document.getElementById('sbUrl')?.value.trim() || DEFAULT_SUPABASE_URL; const anonKey = document.getElementById('sbKey')?.value.trim() || ''; localStorage.setItem(CONFIG_KEY, JSON.stringify({ url, anonKey, schema: 'skillio' })); supabaseClient = null; initCloud().then(() => notify('Supabase Config gespeichert.')); }
async function getCloudClient() { const config = getStoredConfig(); if (!config.anonKey) { state.sync = 'anon key fehlt'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); return null; } if (!window.supabase?.createClient) { state.sync = 'supabase js fehlt'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); return null; } if (!supabaseClient) supabaseClient = window.supabase.createClient(config.url, config.anonKey, { db: { schema: config.schema || 'skillio' } }); return supabaseClient; }
async function initCloud() { const client = await getCloudClient(); if (!client) return; const result = await client.auth.getUser(); cloudUser = result.data?.user || null; if (cloudUser) { state.userEmail = cloudUser.email || state.userEmail; state.sync = 'angemeldet'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); await pullCloudState(); } else { state.sync = 'nicht angemeldet'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); } client.auth.onAuthStateChange((_event, session) => { cloudUser = session?.user || null; if (cloudUser) { state.userEmail = cloudUser.email || ''; state.sync = 'angemeldet'; saveState('auth'); pullCloudState(); } else { state.sync = 'nicht angemeldet'; saveState('auth'); render(); } }); }
async function login(mode) { const client = await getCloudClient(); if (!client) return notify('Bitte zuerst Supabase Anon Key im Profil speichern.'); const email = document.getElementById('authEmail')?.value.trim(); const password = document.getElementById('authPassword')?.value; if (!email || !password) return notify('E-Mail und Passwort eingeben.'); state.userEmail = email; localStorage.setItem(STORE_KEY, JSON.stringify(state)); const response = mode === 'signup' ? await client.auth.signUp({ email, password }) : await client.auth.signInWithPassword({ email, password }); if (response.error) return notify(response.error.message); cloudUser = response.data?.user || response.data?.session?.user || null; state.sync = cloudUser ? 'angemeldet' : 'bestätigung offen'; saveState('login'); await pushCloudState('login'); render(); }
async function logout() { const client = await getCloudClient(); if (client) await client.auth.signOut(); cloudUser = null; state.sync = 'abgemeldet'; saveState('logout'); render(); }
function scheduleCloudSave(reason) { if (isHydrating || !cloudUser) return; clearTimeout(cloudTimer); cloudTimer = setTimeout(() => pushCloudState(reason), 550); }
async function pushCloudState(reason = 'manual') { const client = await getCloudClient(); if (!client) return; if (!cloudUser) { const userResult = await client.auth.getUser(); cloudUser = userResult.data?.user || null; } if (!cloudUser) return notify('Nicht angemeldet. Fortschritt bleibt lokal.'); const payload = { ...state, sync: 'synced', pushedReason: reason }; const response = await client.from('user_learning_state').upsert({ user_id: cloudUser.id, category_id: CATEGORY_ID, state_payload: payload, xp: state.xp, mastery: mastery(), updated_at: new Date().toISOString() }, { onConflict: 'user_id,category_id' }); if (response.error) { state.sync = 'db fehler'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); notify(response.error.message); return; } await client.from('learning_events').insert({ user_id: cloudUser.id, category_id: CATEGORY_ID, event_type: reason, event_payload: { xp: state.xp, mastery: mastery(), route: state.route } }); state.sync = 'synced'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); }
async function pullCloudState() { const client = await getCloudClient(); if (!client || !cloudUser) return; const response = await client.from('user_learning_state').select('state_payload,updated_at').eq('user_id', cloudUser.id).eq('category_id', CATEGORY_ID).maybeSingle(); if (response.error) { state.sync = 'db fehler'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); notify(response.error.message); return; } if (response.data?.state_payload) { isHydrating = true; const remote = response.data.state_payload; state = { ...defaultState(), ...state, ...remote, sync: 'synced', lastRemoteUpdate: response.data.updated_at || new Date().toISOString() }; localStorage.setItem(STORE_KEY, JSON.stringify(state)); isHydrating = false; notify('Cloud-Lernstand geladen.'); render(); } else { await pushCloudState('initial-create'); } }

function bind() { document.querySelectorAll('[data-route]').forEach(btn => btn.addEventListener('click', event => { event.preventDefault(); routeTo(btn.dataset.route); })); document.querySelectorAll('[data-track]').forEach(btn => btn.addEventListener('click', () => { state.track = btn.dataset.track; saveState('track'); render(); })); document.querySelectorAll('[data-track-open]').forEach(btn => btn.addEventListener('click', () => { state.track = btn.dataset.trackOpen; const first = filteredLessons()[0]; if (first) state.lesson = first.id; state.route = 'learn'; saveState('track-open'); render(); })); document.querySelectorAll('[data-lesson]').forEach(btn => btn.addEventListener('click', () => { state.lesson = btn.dataset.lesson; state.route = 'learn'; saveState('lesson'); render(); })); document.querySelectorAll('[data-done]').forEach(btn => btn.addEventListener('click', () => { if (!state.done.includes(btn.dataset.done)) { state.done.push(btn.dataset.done); addXp(40, 'Lektion verstanden'); render(); } else notify('Bereits abgeschlossen.'); })); document.querySelectorAll('[data-qfilter]').forEach(btn => btn.addEventListener('click', () => { state.questionFilter = btn.dataset.qfilter; saveState('question-filter'); render(); })); document.querySelectorAll('[data-q]').forEach(btn => btn.addEventListener('click', () => { const index = Number(btn.dataset.q); if (Object.prototype.hasOwnProperty.call(state.quiz, index)) return; const correct = questions[index].a === Number(btn.dataset.choice); state.quiz[index] = correct; addXp(correct ? 24 : 6, correct ? 'Quiz richtig' : 'Quiz versucht'); render(); })); document.querySelector('[data-resetquiz]')?.addEventListener('click', () => { state.quiz = {}; saveState('reset quiz'); render(); }); document.querySelectorAll('[data-card]').forEach(btn => btn.addEventListener('click', () => { state.card = Number(btn.dataset.card); saveState('card'); render(); })); document.querySelector('[data-reveal]')?.addEventListener('click', () => document.getElementById('activeFlash')?.classList.add('revealed')); document.querySelector('[data-master]')?.addEventListener('click', () => { if (!state.known[state.card]) { state.known[state.card] = new Date().toISOString(); addXp(18, 'Lernkarte gemeistert'); render(); } }); document.querySelectorAll('[data-savecase]').forEach(btn => btn.addEventListener('click', () => { const id = btn.dataset.savecase; const text = document.querySelector(`[data-case-text="${id}"]`)?.value.trim() || ''; if (text.length < 40) return notify('Schreibe mindestens 40 Zeichen.'); const first = !state.caseAnswers[id]; state.caseAnswers[id] = text; addXp(first ? 55 : 12, first ? 'Case bearbeitet' : 'Case aktualisiert'); render(); })); document.querySelectorAll('[data-model]').forEach(btn => btn.addEventListener('click', () => { const item = cases.find(c => c.id === btn.dataset.model); const box = document.getElementById('case-' + btn.dataset.model); if (item && box) { box.classList.remove('hidden'); box.innerHTML = '<strong>Musterlogik:</strong> ' + safe(item.model); } })); document.querySelectorAll('[data-tpl]').forEach(btn => btn.addEventListener('click', () => { const templates = { case:'Die Domäne Leistungen will ein Datenprodukt, übernimmt aber keine Verantwortung.', story:'Formuliere eine Change Story für föderiertes Data-Mesh-Enablement.', adkar:'Analysiere Domänenleitung, Product Owner, Embedded Key User, Mesh Hub und Linienführung mit ADKAR.', roadmap:'Erstelle einen 30/60/90-Tage-Plan für föderiertes Enablement.' }; document.getElementById('coachIn').value = templates[btn.dataset.tpl] || ''; })); document.querySelector('[data-coachrun]')?.addEventListener('click', () => { document.getElementById('coachOut').textContent = coachAnswer(document.getElementById('coachIn').value); addXp(12, 'Coach genutzt'); }); document.querySelector('[data-save-config]')?.addEventListener('click', saveConfigFromForm); document.querySelector('[data-login]')?.addEventListener('click', () => login('login')); document.querySelector('[data-signup]')?.addEventListener('click', () => login('signup')); document.querySelector('[data-logout]')?.addEventListener('click', logout); document.querySelectorAll('[data-sync-now]').forEach(btn => btn.addEventListener('click', () => pushCloudState('manual'))); document.querySelector('[data-reset]')?.addEventListener('click', () => { if (confirm('Lokalen Fortschritt wirklich zurücksetzen?')) { localStorage.removeItem(STORE_KEY); state = defaultState(); render(); } }); }
function render() { document.body.classList.toggle('light', state.theme === 'light'); app.innerHTML = ({ dashboard, learn, practice, coach, profile }[state.route] || dashboard)(); bind(); updateNav(); }
document.getElementById('themeToggle').addEventListener('click', () => { state.theme = state.theme === 'light' ? 'dark' : 'light'; saveState('theme'); render(); });
document.getElementById('syncButton').addEventListener('click', () => pushCloudState('topbar'));
window.addEventListener('hashchange', () => { const route = location.hash.slice(1) || 'dashboard'; if (route !== state.route) routeTo(route); });
if (location.hash) state.route = location.hash.slice(1);
render();
initCloud().then(render).catch(error => { console.warn(error); state.sync = 'cloud init fehler'; localStorage.setItem(STORE_KEY, JSON.stringify(state)); render(); });
if ('serviceWorker' in navigator && location.protocol !== 'file:') window.addEventListener('load', () => navigator.serviceWorker.register('service-worker.js').catch(console.warn));
